class Solution {
public:
    vector<int> powerfulIntegers(int x, int y, int bound) {
        unordered_set<int> res;
        int i = 0;
        while (pow(x, i) <= bound) {
            int j = 0;
            while (pow(x, i) + pow(y, j) <= bound) {
                res.insert(pow(x, i) + pow(y, j));
                if (y == 1) break;
                j++;
            }
            if (x == 1) break;
            i++;
        }
        vector<int> ans(res.begin(), res.end());
        return ans;
    }
};
